import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import studentsImage from '../assets/images/png7.jpg'; 
import studentProfileImage from '../assets/images/png1.jpg';

const AboutSection = ({ showAllFeatures = false }) => {
    const { t } = useTranslation();
    const sectionRef = useRef(null);
    const [activeFeature, setActiveFeature] = useState(null);
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                }
            });
        }, { threshold: 0.1 });

        if (sectionRef.current) {
            observer.observe(sectionRef.current);
        }

        return () => {
            if (sectionRef.current) {
                observer.unobserve(sectionRef.current);
            }
        };
    }, []);

    const coreFeatures = [
        {
            icon: "handshake",
            title: t('aboutSection.features.partnerships.title'),
            description: t('aboutSection.features.partnerships.description'),
            highlight: t('aboutSection.features.partnerships.highlight'),
            gradient: "from-blue-500 to-cyan-500",
            bgGradient: "from-blue-50 to-cyan-50"
        },
        {
            icon: "psychology",
            title: t('aboutSection.features.instructors.title'),
            description: t('aboutSection.features.instructors.description'),
            highlight: t('aboutSection.features.instructors.highlight'),
            gradient: "from-emerald-500 to-teal-500",
            bgGradient: "from-emerald-50 to-teal-50"
        },
        {
            icon: "dashboard",
            title: t('aboutSection.features.facilities.title'),
            description: t('aboutSection.features.facilities.description'),
            highlight: t('aboutSection.features.facilities.highlight'),
            gradient: "from-amber-500 to-orange-500",
            bgGradient: "from-amber-50 to-orange-50"
        },
        {
            icon: "rocket_launch",
            title: t('aboutSection.features.career.title'),
            description: t('aboutSection.features.career.description'),
            highlight: t('aboutSection.features.career.highlight'),
            gradient: "from-purple-500 to-pink-500",
            bgGradient: "from-purple-50 to-pink-50"
        }
    ];

    const additionalFeatures = [
        {
            icon: "verified",
            title: t('aboutSection.features.certifications.title'),
            description: t('aboutSection.features.certifications.description'),
            highlight: t('aboutSection.features.certifications.highlight'),
            gradient: "from-rose-500 to-pink-500",
            bgGradient: "from-rose-50 to-pink-50"
        },
        {
            icon: "support_agent",
            title: t('aboutSection.features.support.title'),
            description: t('aboutSection.features.support.description'),
            highlight: t('aboutSection.features.support.highlight'),
            gradient: "from-teal-500 to-cyan-500",
            bgGradient: "from-teal-50 to-cyan-50"
        }
    ];

    const displayFeatures = showAllFeatures ? 
        [...coreFeatures, ...additionalFeatures] : 
        coreFeatures;

    return (
        <section ref={sectionRef} className="relative py-20 bg-gradient-to-br from-gray-50 via-white to-blue-50 overflow-hidden">
            {/* Animated Background Elements */}
            <div className="absolute inset-0 overflow-hidden">
                <div className="absolute -top-40 -right-40 w-80 h-80 bg-gradient-to-br from-blue-400/20 to-purple-400/20 rounded-full blur-3xl animate-pulse"></div>
                <div className="absolute -bottom-40 -left-40 w-96 h-96 bg-gradient-to-br from-cyan-400/20 to-teal-400/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
                <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-gradient-to-br from-purple-400/10 to-pink-400/10 rounded-full blur-2xl animate-pulse delay-500"></div>
            </div>

            <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                {/* Header Section */}
                <div className={`text-center mb-20 transition-all duration-1000 ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
                    <div className="inline-flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-full text-sm font-bold mb-6 shadow-lg">
                        <span className="material-icons text-sm">info</span>
                        {t('aboutSection.header.badge')}
                    </div>
                    <h2 className="text-5xl md:text-6xl font-extrabold text-gray-900 mb-6 leading-tight">
                        <span className="bg-gradient-to-r from-blue-600 via-purple-600 to-cyan-600 bg-clip-text text-transparent">
                            {t('aboutSection.header.title')}
                        </span>
                    </h2>
                    <p className="text-xl text-gray-600 max-w-4xl mx-auto leading-relaxed">
                        {t('aboutSection.header.subtitle')}
                    </p>
                </div>

                {/* Features Grid */}
                <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8 mb-20">
                    {displayFeatures.map((feature, index) => (
                        <div 
                            key={index}
                            className={`group relative bg-white rounded-2xl p-8 shadow-xl hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-2 cursor-pointer overflow-hidden ${
                                isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'
                            }`}
                            style={{ transitionDelay: `${index * 150}ms` }}
                            onMouseEnter={() => setActiveFeature(index)}
                            onMouseLeave={() => setActiveFeature(null)}
                        >
                            {/* Gradient Background Overlay */}
                            <div className={`absolute inset-0 bg-gradient-to-br ${feature.bgGradient} opacity-0 group-hover:opacity-100 transition-opacity duration-300`}></div>

                            {/* Icon */}
                            <div className={`relative w-16 h-16 rounded-2xl bg-gradient-to-br ${feature.gradient} flex items-center justify-center mb-6 group-hover:scale-110 transition-transform duration-300`}>
                                <span className="material-icons text-2xl text-white">{feature.icon}</span>
                            </div>

                            {/* Content */}
                            <div className="relative z-10">
                                <h3 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-gray-800">
                                    {feature.title}
                                </h3>
                                <p className="text-gray-600 text-sm leading-relaxed mb-4 group-hover:text-gray-700">
                                    {feature.description}
                                </p>
                                <div className={`inline-flex items-center px-3 py-1 rounded-full bg-gradient-to-r ${feature.gradient} text-white text-xs font-bold`}>
                                    {feature.highlight}
                                </div>
                            </div>

                            {/* Hover Effect Border */}
                            <div className={`absolute inset-0 rounded-2xl border-2 border-transparent bg-gradient-to-br ${feature.gradient} opacity-0 group-hover:opacity-100 transition-opacity duration-300`} style={{ mask: 'linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0)', maskComposite: 'xor' }}></div>
                        </div>
                    ))}
                </div>

                {/* CTA Section */}
                {!showAllFeatures && (
                    <div className={`bg-white rounded-3xl shadow-2xl overflow-hidden mb-16 transition-all duration-1000 ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`} style={{ transitionDelay: '600ms' }}>
                        <div className="grid lg:grid-cols-2 gap-0">
                            {/* Image Side */}
                            <div className="relative h-64 lg:h-auto overflow-hidden">
                                <img 
                                    src={studentsImage} 
                                    alt={t('aboutSection.cta.imageAlt')}
                                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                                />
                                <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
                            </div>

                            {/* Content Side */}
                            <div className="p-8 lg:p-12 flex flex-col justify-center">
                                <div className="inline-flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-green-500 to-emerald-500 text-white rounded-full text-sm font-bold mb-6 w-fit">
                                    <span className="material-icons text-sm">trending_up</span>
                                    {t('aboutSection.cta.badge')}
                                </div>
                                <h3 className="text-3xl lg:text-4xl font-bold text-gray-900 mb-4">
                                    {t('aboutSection.cta.title')}
                                </h3>
                                <p className="text-gray-600 text-lg leading-relaxed mb-8">
                                    {t('aboutSection.cta.description')}
                                </p>

                                {/* Stats */}
                                <div className="flex gap-8 mb-8">
                                    <div className="text-center">
                                        <div className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">15+</div>
                                        <div className="text-sm text-gray-600 font-medium">{t('aboutSection.cta.stats.years')}</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-3xl font-bold bg-gradient-to-r from-green-600 to-emerald-600 bg-clip-text text-transparent">5,000+</div>
                                        <div className="text-sm text-gray-600 font-medium">{t('aboutSection.cta.stats.graduates')}</div>
                                    </div>
                                </div>

                                <Link 
                                    to="/about" 
                                    className="inline-flex items-center gap-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-4 rounded-xl font-bold text-lg hover:from-blue-700 hover:to-purple-700 transition-all duration-300 shadow-lg hover:shadow-xl transform hover:scale-105 w-fit"
                                >
                                    {t('aboutSection.cta.button')}
                                    <span className="material-icons">arrow_forward</span>
                                </Link>
                            </div>
                        </div>
                    </div>
                )}

                {/* Testimonial Section */}
                <div className={`max-w-4xl mx-auto transition-all duration-1000 ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`} style={{ transitionDelay: '800ms' }}>
                    <div className="bg-gradient-to-br from-blue-600 to-purple-600 rounded-3xl p-8 lg:p-12 text-white relative overflow-hidden">
                        {/* Background Pattern */}
                        <div className="absolute inset-0 opacity-10">
                            <div className="absolute top-0 right-0 w-64 h-64 rounded-full bg-white transform translate-x-32 -translate-y-32"></div>
                            <div className="absolute bottom-0 left-0 w-48 h-48 rounded-full bg-white transform -translate-x-24 translate-y-24"></div>
                        </div>

                        <div className="relative z-10">
                            <div className="flex items-start gap-4 mb-6">
                                <span className="material-icons text-4xl text-yellow-300">format_quote</span>
                                <blockquote className="text-xl lg:text-2xl font-medium leading-relaxed italic">
                                    {t('aboutSection.testimonial.quote')}
                                </blockquote>
                            </div>

                            <div className="flex items-center gap-4">
                                <img 
                                    src={studentProfileImage} 
                                    alt={t('aboutSection.testimonial.author.name')}
                                    className="w-16 h-16 rounded-full border-4 border-white/20 object-cover"
                                />
                                <div>
                                    <div className="font-bold text-lg">{t('aboutSection.testimonial.author.name')}</div>
                                    <div className="text-blue-100">{t('aboutSection.testimonial.author.title')}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default AboutSection;
